<style>
  .mascot-logo {
    display: inline-block;
    color: var(--teal, #00754A);
    overflow: visible;
  }
  
  .wing-left, .wing-right {
    transform-origin: 512px 512px;
    transition: transform 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
  }
  
  /* Always flapping (for loaders) */
  .mascot-logo.always .wing-left {
    animation: flap-left 0.5s ease-in-out infinite;
  }
  .mascot-logo.always .wing-right {
    animation: flap-right 0.5s ease-in-out infinite;
  }
  
  /* Hover flapping (for headers/links) */
  .mascot-logo.hover:hover .wing-left,
  :global(a:hover) .mascot-logo.hover .wing-left,
  :global(.group:hover) .mascot-logo.hover .wing-left {
    animation: flap-left 0.75s ease-in-out;
  }
  .mascot-logo.hover:hover .wing-right,
  :global(a:hover) .mascot-logo.hover .wing-right,
  :global(.group:hover) .mascot-logo.hover .wing-right {
    animation: flap-right 0.75s ease-in-out;
  }
  
  @keyframes flap-left {
    0%, 100% { transform: scaleX(1) rotate(0deg); }
    15% { transform: scaleX(0.35) rotate(-5deg); }
    30% { transform: scaleX(0.9) rotate(3deg); }
    45% { transform: scaleX(0.45) rotate(-3deg); }
    60% { transform: scaleX(0.85) rotate(1deg); }
    78% { transform: scaleX(0.65) rotate(-1deg); }
  }
  
  @keyframes flap-right {
    0%, 100% { transform: scaleX(1) rotate(0deg); }
    15% { transform: scaleX(0.35) rotate(5deg); }
    30% { transform: scaleX(0.9) rotate(-3deg); }
    45% { transform: scaleX(0.45) rotate(3deg); }
    60% { transform: scaleX(0.85) rotate(-1deg); }
    78% { transform: scaleX(0.65) rotate(1deg); }
  }
  
  /* Respect prefers-reduced-motion */
  @media (prefers-reduced-motion: reduce) {
    .wing-left, .wing-right {
      animation: none !important;
      transform: none !important;
    }
  }
</style>
